import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Btn, Input } from '../components/ui';
import { Shield } from 'lucide-react';

const DEMO_USERS = [
  { label: 'Admin',      email: 'admin@uni.edu',      password: 'admin123',  role: 'admin' },
  { label: 'HR',         email: 'hr@uni.edu',         password: 'hr123',     role: 'hr' },
  { label: 'HOD',        email: 'hod.cs@uni.edu',     password: 'hod123',    role: 'department_head' },
  { label: 'Accountant', email: 'accountant@uni.edu', password: 'acc123',    role: 'accountant' },
  { label: 'Employee',   email: 'employee@uni.edu',   password: 'emp123',    role: 'employee' },
];

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login, loading } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    if (!email || !password) {
      setError('Please enter both email and password');
      return;
    }
    const result = await login(email, password);
    if (result.ok) {
      navigate('/dashboard');
    } else {
      setError(result.error);
    }
  };

  const fillDemo = (user) => {
    setEmail(user.email);
    setPassword(user.password);
    setError('');
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-logo">
          <div className="logo-icon">
            <Shield size={28} color="#fff" strokeWidth={2} />
          </div>
          <h1>UniHRM</h1>
          <p>University Human Resource Management</p>
        </div>

        <form onSubmit={handleSubmit}>
          <Input
            label="Email address"
            type="email"
            placeholder="Enter your email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            autoComplete="email"
            id="login-email"
          />
          <Input
            label="Password"
            type="password"
            placeholder="Enter your password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            autoComplete="current-password"
            id="login-password"
          />

          {error && (
            <div
              style={{
                background: 'var(--danger-light)',
                border: '1px solid var(--danger-border)',
                color: 'var(--danger)',
                padding: '10px 14px',
                borderRadius: 'var(--radius)',
                fontSize: 13,
                marginBottom: 16,
                fontWeight: 500,
              }}
            >
              {error}
            </div>
          )}

          <Btn
            type="submit"
            loading={loading}
            style={{ width: '100%', padding: '11px 20px', fontSize: 15, fontWeight: 600 }}
            id="login-submit"
          >
            {loading ? 'Signing in...' : 'Sign In'}
          </Btn>
        </form>

        <div className="demo-logins">
          <h4>Quick Demo Login</h4>
          <div className="demo-pills">
            {DEMO_USERS.map((u) => (
              <button
                key={u.role}
                className="demo-pill"
                onClick={() => fillDemo(u)}
                id={`demo-${u.role}`}
              >
                {u.label}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
